module top_module(
    input clk,
    input load,
    input shift_left,
    input shift_right,
    input reset,
    input [3:0] data_in,
    output [3:0] data_out
);reg [3:0] data_reg;

always @(posedge clk) begin
    if (reset) begin
        data_reg <= 4'b0;
    end else if (load) begin
        data_reg <= data_in;
    end else if (shift_left) begin
        data_reg <= {data_reg[2:0], 1'b0};
    end else if (shift_right) begin
        data_reg <= {1'b0, data_reg[3:1]};
    end
end

assign data_out = data_reg;

endmodule
